import React from 'react';
import { ScenarioResult } from '../types';
import { FileDown, CheckCircle2, Play, Loader2, MessageSquare, AlertTriangle, CheckCircle, AlertCircle, PlayCircle } from 'lucide-react';

interface ScenarioPreviewProps {
  scenarios: ScenarioResult[];
  onDownload: () => void;
  onRunSimulation: (id: number) => void;
  onRunAllSimulations: () => void;
  onViewChat: (id: number) => void;
  isBulkTesting: boolean;
}

export const ScenarioPreview: React.FC<ScenarioPreviewProps> = ({ 
  scenarios, 
  onDownload, 
  onRunSimulation,
  onRunAllSimulations,
  onViewChat,
  isBulkTesting
}) => {
  if (scenarios.length === 0) return null;

  const testedCount = scenarios.filter(s => s.simulationStatus === 'completed').length;
  const progressPercent = Math.round((testedCount / scenarios.length) * 100);

  return (
    <div className="mt-8 bg-white rounded-xl shadow-lg border border-gray-200 overflow-hidden animate-fade-in-up">
      <div className="bg-indigo-50 p-4 border-b border-indigo-100 flex flex-col sm:flex-row justify-between items-center gap-4">
        <div className="flex-1">
          <h2 className="text-lg font-bold text-gray-800 flex items-center gap-2">
            <CheckCircle2 className="text-green-600 w-5 h-5" />
            Generated Scenarios Preview
          </h2>
          <div className="flex items-center gap-3 mt-1">
            <p className="text-sm text-gray-600">
              {scenarios.length} scenarios generated.
            </p>
            {isBulkTesting && (
              <div className="flex items-center gap-2">
                <div className="w-24 h-1.5 bg-gray-200 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-indigo-600 transition-all duration-500" 
                    style={{ width: `${progressPercent}%` }}
                  />
                </div>
                <span className="text-xs font-medium text-indigo-600">{testedCount}/{scenarios.length}</span>
              </div>
            )}
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button
            onClick={onRunAllSimulations}
            disabled={isBulkTesting}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-lg font-medium shadow-sm transition-all transform hover:scale-105 ${
              isBulkTesting 
                ? 'bg-gray-100 text-gray-400 cursor-not-allowed border border-gray-200' 
                : 'bg-indigo-600 text-white hover:bg-indigo-700'
            }`}
          >
            {isBulkTesting ? (
              <>
                <Loader2 className="w-5 h-5 animate-spin" />
                Testing All...
              </>
            ) : (
              <>
                <PlayCircle className="w-5 h-5" />
                Test All Scenarios
              </>
            )}
          </button>

          <button
            onClick={onDownload}
            disabled={isBulkTesting}
            className="flex items-center gap-2 px-6 py-2.5 bg-green-600 text-white rounded-lg hover:bg-green-700 font-medium shadow-sm transition-all transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <FileDown className="w-5 h-5" />
            Download Excel
          </button>
        </div>
      </div>

      <div className="p-0">
        <div className="max-h-[600px] overflow-y-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50 sticky top-0 z-10 shadow-sm">
              <tr>
                <th scope="col" className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider w-12">
                  No.
                </th>
                <th scope="col" className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider w-[40%]">
                  Scenario Description
                </th>
                <th scope="col" className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider w-[30%]">
                  Bot Behavior Issue (AI Analysis)
                </th>
                <th scope="col" className="px-4 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider w-[20%]">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {scenarios.map((scenario) => (
                <tr key={scenario.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-4 py-3 whitespace-nowrap text-sm font-medium text-gray-900">
                    {scenario.id}
                  </td>
                  <td className="px-4 py-3 text-sm text-gray-700 align-top">
                    {scenario.text}
                  </td>
                  <td className="px-4 py-3 text-sm text-gray-700 align-top">
                    {scenario.simulationStatus === 'completed' && scenario.analysis ? (
                      <div className={`p-2 rounded text-xs border ${
                        scenario.analysis.toLowerCase().includes('no issues') 
                          ? 'bg-green-50 text-green-700 border-green-200' 
                          : 'bg-amber-50 text-amber-800 border-amber-200'
                      }`}>
                        {scenario.analysis.toLowerCase().includes('no issues') ? (
                          <div className="flex gap-1">
                             <CheckCircle className="w-3 h-3 mt-0.5 flex-shrink-0" />
                             {scenario.analysis}
                          </div>
                        ) : (
                          <div className="flex gap-1">
                             <AlertTriangle className="w-3 h-3 mt-0.5 flex-shrink-0" />
                             {scenario.analysis}
                          </div>
                        )}
                      </div>
                    ) : scenario.simulationStatus === 'error' ? (
                      <span className="text-red-500 text-xs flex items-center gap-1">
                        <AlertCircle className="w-3 h-3" /> Simulation Failed
                      </span>
                    ) : (
                      <span className="text-gray-400 italic text-xs">Run test to analyze</span>
                    )}
                  </td>
                  <td className="px-4 py-3 text-center align-middle whitespace-nowrap">
                    {scenario.simulationStatus === 'idle' || scenario.simulationStatus === 'error' ? (
                       <button
                         onClick={() => onRunSimulation(scenario.id)}
                         disabled={isBulkTesting}
                         className="inline-flex items-center gap-1.5 px-3 py-1.5 border border-indigo-600 text-indigo-600 rounded-md text-xs font-medium hover:bg-indigo-50 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                       >
                         <Play className="w-3 h-3" />
                         Test Scenario
                       </button>
                    ) : scenario.simulationStatus === 'running' ? (
                       <span className="inline-flex items-center gap-1.5 px-3 py-1.5 text-gray-500 text-xs font-medium">
                         <Loader2 className="w-3 h-3 animate-spin" />
                         Running...
                       </span>
                    ) : (
                       <div className="flex flex-col items-center gap-2">
                         <button
                           onClick={() => onViewChat(scenario.id)}
                           className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-indigo-600 text-white rounded-md text-xs font-medium hover:bg-indigo-700 transition-colors shadow-sm"
                         >
                           <MessageSquare className="w-3 h-3" />
                           View Chat
                         </button>
                         <button
                           onClick={() => onRunSimulation(scenario.id)}
                           disabled={isBulkTesting}
                           className="text-[10px] text-gray-400 hover:text-indigo-600 hover:underline disabled:opacity-50"
                         >
                           Re-run
                         </button>
                       </div>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { VoicebotFormData, ScenarioResult } from './types';
import { EntityList } from './components/EntityList';
import { ScenarioPreview } from './components/ScenarioPreview';
import { generateScenarios, simulateScenario } from './services/geminiService';
import { downloadExcel } from './services/excelBuilder';
import { ChatModal } from './components/ChatModal';
import { Bot, FileText, Target, ListChecks, Wand2, Loader2, Info, Layout, User } from 'lucide-react';

const App: React.FC = () => {
  const [formData, setFormData] = useState<VoicebotFormData>({
    agentName: '',
    leadName: '',
    voicebotName: '',
    businessUseCase: '',
    mainPrompt: '',
    entityPrompt: '',
    entitiesJson: '',
    includeHappyPath: true,
    includeEdgeCases: true,
    includeNegative: true,
    includeEntitySpecific: true,
    promptMode: 'both',
  });

  const [loading, setLoading] = useState(false);
  const [isBulkTesting, setIsBulkTesting] = useState(false);
  const [generatedScenarios, setGeneratedScenarios] = useState<ScenarioResult[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Simulation & Chat Modal State
  const [chatModalOpen, setChatModalOpen] = useState(false);
  const [selectedScenarioForChat, setSelectedScenarioForChat] = useState<ScenarioResult | null>(null);

  const handleInputChange = (field: keyof VoicebotFormData, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validate JSON before submission ONLY if the section is visible (not 'main' mode)
    if (formData.promptMode !== 'main') {
      if (!formData.entitiesJson.trim()) {
        setError("Please input the entities JSON.");
        return;
      }

      try {
        const parsed = JSON.parse(formData.entitiesJson);
        if (Object.keys(parsed).length === 0) {
          setError("Please provide at least one entity in the JSON object.");
          return;
        }
      } catch (e) {
        setError("Invalid JSON format in Entities field. Please fix syntax errors.");
        return;
      }
    }

    setLoading(true);
    setError(null);
    setGeneratedScenarios([]);

    try {
      const scenarios = await generateScenarios(formData);
      const results: ScenarioResult[] = scenarios.map((text, index) => ({
        id: index + 1,
        text,
        simulationStatus: 'idle'
      }));
      setGeneratedScenarios(results);
    } catch (err: any) {
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setLoading(false);
    }
  };

  const handleDownload = () => {
    if (generatedScenarios.length > 0) {
      const fileName = formData.voicebotName.trim() || "Voicebot";
      downloadExcel(generatedScenarios, fileName, formData.promptMode);
    }
  };

  const handleRunSimulation = async (id: number): Promise<void> => {
    // 1. Set status to running
    setGeneratedScenarios(prev => prev.map(s => 
      s.id === id ? { ...s, simulationStatus: 'running', error: undefined } : s
    ));

    // Get current state to find the scenario text
    // Note: We use a functional update for setting the result later, 
    // but we need the scenario text now.
    const scenario = generatedScenarios.find(s => s.id === id);
    if (!scenario) return;

    try {
      // 2. Run Simulation
      const result = await simulateScenario(scenario.text, formData);

      // 3. Update with results
      setGeneratedScenarios(prev => prev.map(s => 
        s.id === id ? { 
          ...s, 
          simulationStatus: 'completed', 
          transcript: result.transcript,
          analysis: result.analysis
        } : s
      ));
    } catch (err: any) {
      // 4. Handle Error
      setGeneratedScenarios(prev => prev.map(s => 
        s.id === id ? { ...s, simulationStatus: 'error', error: err.message } : s
      ));
    }
  };

  const handleRunAllSimulations = async () => {
    if (isBulkTesting || generatedScenarios.length === 0) return;

    setIsBulkTesting(true);

    // We run them sequentially to ensure "quality" (no API congestion) 
    // and to not mix processes.
    for (const scenario of generatedScenarios) {
      // Only test scenarios that haven't been completed or are not currently running
      // or if user wants to force re-test them all. Let's re-test all idle/error ones.
      if (scenario.simulationStatus !== 'completed') {
        await handleRunSimulation(scenario.id);
      }
    }

    setIsBulkTesting(false);
  };

  const handleViewChat = (id: number) => {
    const scenario = generatedScenarios.find(s => s.id === id);
    if (scenario && scenario.transcript) {
      setSelectedScenarioForChat(scenario);
      setChatModalOpen(true);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 py-10 px-4 sm:px-6 lg:px-8">
      <div className="max-w-5xl mx-auto">

        {/* Header */}
        <div className="text-center mb-10">
          <div className="flex justify-center mb-4">
            <div className="bg-indigo-600 p-3 rounded-full shadow-lg">
              <Bot className="w-10 h-10 text-white" />
            </div>
          </div>
          <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">
            Voicebot Test Scenario Generator
          </h1>
          <p className="mt-3 text-lg text-gray-600 max-w-2xl mx-auto">
            AI-powered tool to create comprehensive test cases for your conversational AI agents.
          </p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

          {/* Main Form Area */}
          <div className="lg:col-span-2 space-y-6">
            <form onSubmit={handleSubmit} className="bg-white rounded-xl shadow-lg p-6 sm:p-8 space-y-8 border border-gray-100">

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="flex items-center gap-2 text-sm font-semibold text-gray-700 mb-2">
                    <User className="w-4 h-4 text-indigo-500" />
                    Agent Name
                  </label>
                  <input
                    type="text"
                    className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-3 text-gray-700 border"
                    placeholder="e.g. John Doe"
                    value={formData.agentName}
                    onChange={(e) => handleInputChange('agentName', e.target.value)}
                  />
                </div>
                <div>
                  <label className="flex items-center gap-2 text-sm font-semibold text-gray-700 mb-2">
                    <User className="w-4 h-4 text-indigo-500" />
                    Lead Name
                  </label>
                  <input
                    type="text"
                    className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-3 text-gray-700 border"
                    placeholder="e.g. Jane Smith"
                    value={formData.leadName}
                    onChange={(e) => handleInputChange('leadName', e.target.value)}
                  />
                </div>
              </div>

              <div>
                <label className="flex items-center gap-2 text-sm font-semibold text-gray-700 mb-2">
                  <Bot className="w-4 h-4 text-indigo-500" />
                  Name of Voicebot
                </label>
                <input
                  type="text"
                  required
                  className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-3 text-gray-700 border"
                  placeholder="e.g. Parul University Bot"
                  value={formData.voicebotName}
                  onChange={(e) => handleInputChange('voicebotName', e.target.value)}
                />
              </div>

              <div>
                <label className="flex items-center gap-2 text-sm font-semibold text-gray-700 mb-2">
                  <ListChecks className="w-4 h-4 text-indigo-500" />
                  Business Use Case
                </label>
                <textarea
                  required
                  rows={3}
                  className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-3 text-gray-700 border"
                  placeholder="e.g. Insurance company calling for lead qualification..."
                  value={formData.businessUseCase}
                  onChange={(e) => handleInputChange('businessUseCase', e.target.value)}
                />
                <p className="text-xs text-gray-400 mt-1 text-right">{formData.businessUseCase.length} chars</p>
              </div>

              {formData.promptMode !== 'entity' && (
                <div className="animate-fade-in">
                  <label className="flex items-center gap-2 text-sm font-semibold text-gray-700 mb-2">
                    <Target className="w-4 h-4 text-indigo-500" />
                    Main Prompt (Bot Behavior)
                  </label>
                  <textarea
                    required
                    rows={6}
                    className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-3 text-gray-700 border font-mono text-sm"
                    placeholder="You are a friendly insurance sales bot..."
                    value={formData.mainPrompt}
                    onChange={(e) => handleInputChange('mainPrompt', e.target.value)}
                  />
                  <p className="text-xs text-gray-400 mt-1 text-right">{formData.mainPrompt.length} chars</p>
                </div>
              )}

              {formData.promptMode !== 'main' && (
                <div className="animate-fade-in">
                  <label className="flex items-center gap-2 text-sm font-semibold text-gray-700 mb-2">
                    <FileText className="w-4 h-4 text-indigo-500" />
                    Entity Prompt (Extraction Instructions)
                  </label>
                  <textarea
                    required
                    rows={4}
                    className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-3 text-gray-700 border font-mono text-sm"
                    placeholder="Extract call_outcome, budget, etc..."
                    value={formData.entityPrompt}
                    onChange={(e) => handleInputChange('entityPrompt', e.target.value)}
                  />
                </div>
              )}

              {formData.promptMode !== 'main' && (
                <div className="animate-fade-in">
                  <EntityList 
                    jsonValue={formData.entitiesJson} 
                    onChange={(val) => handleInputChange('entitiesJson', val)} 
                  />
                </div>
              )}

              {error && (
                <div className="bg-red-50 text-red-700 p-4 rounded-lg border border-red-200 text-sm flex items-center gap-2 animate-pulse">
                   <Info className="w-5 h-5 flex-shrink-0" />
                   {error}
                </div>
              )}

              <button
                type="submit"
                disabled={loading || isBulkTesting}
                className="w-full flex items-center justify-center gap-2 py-4 px-6 border border-transparent rounded-lg shadow-md text-lg font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-70 disabled:cursor-not-allowed transition-all"
              >
                {loading ? (
                  <>
                    <Loader2 className="w-6 h-6 animate-spin" />
                    Generating Scenarios...
                  </>
                ) : (
                  <>
                    <Wand2 className="w-6 h-6" />
                    Generate Scenarios
                  </>
                )}
              </button>
            </form>
          </div>

          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-lg p-6 border border-gray-100 sticky top-6">

              <h3 className="text-lg font-bold text-gray-900 mb-4 border-b pb-2 flex items-center gap-2">
                <Layout className="w-5 h-5 text-indigo-500" />
                Prompt Focus
              </h3>
              <div className="space-y-3 pt-2 mb-8">
                <label className="flex items-center space-x-3 cursor-pointer p-2 hover:bg-gray-50 rounded-md transition-colors">
                  <input
                    type="radio"
                    name="promptMode"
                    value="main"
                    disabled={isBulkTesting}
                    checked={formData.promptMode === 'main'}
                    onChange={() => handleInputChange('promptMode', 'main')}
                    className="h-5 w-5 text-indigo-600 border-gray-300 focus:ring-indigo-500"
                  />
                  <span className="text-sm text-gray-700">Main prompt</span>
                </label>
                <label className="flex items-center space-x-3 cursor-pointer p-2 hover:bg-gray-50 rounded-md transition-colors">
                  <input
                    type="radio"
                    name="promptMode"
                    value="entity"
                    disabled={isBulkTesting}
                    checked={formData.promptMode === 'entity'}
                    onChange={() => handleInputChange('promptMode', 'entity')}
                    className="h-5 w-5 text-indigo-600 border-gray-300 focus:ring-indigo-500"
                  />
                  <span className="text-sm text-gray-700">Entity prompt</span>
                </label>
                <label className="flex items-center space-x-3 cursor-pointer p-2 hover:bg-gray-50 rounded-md transition-colors">
                  <input
                    type="radio"
                    name="promptMode"
                    value="both"
                    disabled={isBulkTesting}
                    checked={formData.promptMode === 'both'}
                    onChange={() => handleInputChange('promptMode', 'both')}
                    className="h-5 w-5 text-indigo-600 border-gray-300 focus:ring-indigo-500"
                  />
                  <span className="text-sm text-gray-700">Both</span>
                </label>
              </div>

              <h3 className="text-lg font-bold text-gray-900 mb-4 border-b pb-2">Generation Options</h3>

              <div className="space-y-4">
                <div className="space-y-3 pt-2">
                  <label className="flex items-center space-x-3 cursor-pointer p-2 hover:bg-gray-50 rounded-md transition-colors">
                    <input
                      type="checkbox"
                      disabled={isBulkTesting}
                      checked={formData.includeHappyPath}
                      onChange={(e) => handleInputChange('includeHappyPath', e.target.checked)}
                      className="h-5 w-5 text-indigo-600 rounded focus:ring-indigo-500 border-gray-300"
                    />
                    <span className="text-sm text-gray-700">Happy Path Scenarios</span>
                  </label>
                  <label className="flex items-center space-x-3 cursor-pointer p-2 hover:bg-gray-50 rounded-md transition-colors">
                    <input
                      type="checkbox"
                      disabled={isBulkTesting}
                      checked={formData.includeEdgeCases}
                      onChange={(e) => handleInputChange('includeEdgeCases', e.target.checked)}
                      className="h-5 w-5 text-indigo-600 rounded focus:ring-indigo-500 border-gray-300"
                    />
                    <span className="text-sm text-gray-700">Edge Cases</span>
                  </label>
                  <label className="flex items-center space-x-3 cursor-pointer p-2 hover:bg-gray-50 rounded-md transition-colors">
                    <input
                      type="checkbox"
                      disabled={isBulkTesting}
                      checked={formData.includeNegative}
                      onChange={(e) => handleInputChange('includeNegative', e.target.checked)}
                      className="h-5 w-5 text-indigo-600 rounded focus:ring-indigo-500 border-gray-300"
                    />
                    <span className="text-sm text-gray-700">Negative Scenarios</span>
                  </label>
                  <label className="flex items-center space-x-3 cursor-pointer p-2 hover:bg-gray-50 rounded-md transition-colors">
                    <input
                      type="checkbox"
                      disabled={isBulkTesting}
                      checked={formData.includeEntitySpecific}
                      onChange={(e) => handleInputChange('includeEntitySpecific', e.target.checked)}
                      className="h-5 w-5 text-indigo-600 rounded focus:ring-indigo-500 border-gray-300"
                    />
                    <span className="text-sm text-gray-700">Entity-Specific Tests</span>
                  </label>
                </div>

                <div className="pt-4 border-t text-xs text-gray-500 leading-relaxed">
                  <p className="font-semibold mb-1">Note:</p>
                  <p>The AI will generate an exhaustive list of scenarios covering all possible variations. This may take a moment.</p>
                </div>
              </div>
            </div>
          </div>
        </div>

        <ScenarioPreview 
          scenarios={generatedScenarios} 
          onDownload={handleDownload} 
          onRunSimulation={handleRunSimulation}
          onRunAllSimulations={handleRunAllSimulations}
          onViewChat={handleViewChat}
          isBulkTesting={isBulkTesting}
        />

        <ChatModal
          isOpen={chatModalOpen}
          onClose={() => setChatModalOpen(false)}
          transcript={selectedScenarioForChat?.transcript || []}
          agentName={formData.agentName}
          leadName={formData.leadName}
          scenarioText={selectedScenarioForChat?.text || ''}
        />

      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { VoicebotFormData, GeneratedResponse, SimulationResponse, ChatMessage } from "../types";

const processApiKey = process.env.API_KEY;

export const generateScenarios = async (data: VoicebotFormData): Promise<string[]> => {
  if (!processApiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  // Parse Entities JSON
  let entityDescriptions = "";
  // Only parse entities if we are not in 'main' mode, as that mode ignores entities.
  if (data.promptMode !== 'main') {
    try {
      const entities = JSON.parse(data.entitiesJson);
      entityDescriptions = Object.entries(entities)
        .map(([key, value]) => {
          // If value is empty string, just list the key, otherwise list key: value
          const desc = value ? `: ${value}` : "";
          return `- ${key}${desc}`;
        })
        .join("\n");
    } catch (e) {
      throw new Error("Invalid JSON in Entities field. Please correct it before generating scenarios.");
    }
  }

  // Determine context visibility
  const showMain = data.promptMode !== 'entity';
  const showEntity = data.promptMode !== 'main';

  // Define tailored instructions based on mode
  let specificInstructions = "";
  if (data.promptMode === 'main') {
    specificInstructions = `
      STRICT FOCUS: **Bot Behavior, Persona & Conversation Flow**.
      - **Consolidated Happy Paths**: Verify the entire flow (Intro -> Pitch -> Qualify -> Close) in single, comprehensive scenarios.
      - **Context Switching**: Scenarios where user changes topic or asks about something unrelated (e.g., "Is this a real person?", "Who is your manager?") to see if bot stays on track.
      - **Logic Conflicts**: User says something that sounds like a rejection but is actually a negotiation (e.g., "I can't afford that *right now* unless you have a discount").
    `;
  } else if (data.promptMode === 'entity') {
    specificInstructions = `
      STRICT FOCUS: **Outcome-Based Entity Coverage & Ambiguity Resolution**.
      - **CRITICAL TASK**: Analyze the 'Entity Prompt'/'Entities JSON' for ALL possible outcomes.
      - **Logic Traps & Overrides**: Create scenarios that trick simple entity extraction. 
        - **Example**: "Lead had already purchased another old course but shows interest in the new one" -> Outcome must be 'Interested', NOT 'Already Purchased'.
      - **For EACH outcome**: Generate standard cases AND tricky edge cases.
    `;
  } else {
    specificInstructions = `
      STRICT FOCUS: **Comprehensive & Complex Integration Testing**.
      - Test the intersection of Bot Logic and Data Extraction.
      - **Complex User Journeys**: Multi-turn conversations where intent is not obvious until the end.
      - **Implicit Intents**: User gives data without being explicitly asked, or gives partial data that requires follow-up.
    `;
  }

  const ai = new GoogleGenAI({ apiKey: processApiKey });

  const prompt = `
    You are an elite QA Automation Architect for conversational AI.

    YOUR DUAL OBJECTIVE:
    1. **SMART CONSOLIDATION (Efficiency)**: Do NOT generate fragmented tests. If a standard call flow covers multiple stages (e.g., Intro -> Pitch -> Qualification -> Closing), combine them into ONE "Happy Path" scenario.
    2. **REALITY STRESS TESTING (The "Out of the Box")**: You must generate creative scenarios for unexpected user behaviors, specifically tailored to the **Indian Market**.

    BUSINESS CONTEXT:
    ${data.businessUseCase}

    ${showMain ? `BOT BEHAVIOR (Main Prompt):\n${data.mainPrompt}` : ""}

    ${showEntity ? `ENTITY EXTRACTION (Entity Prompt):\n${data.entityPrompt}` : ""}

    ${entityDescriptions ? `ENTITIES TO EXTRACT:\n${entityDescriptions}` : ""}

    ${specificInstructions}

    ---------------------------------------------------
    SECTION 1: SMART COVERAGE & CONSOLIDATION
    ---------------------------------------------------
    Analyze the provided prompts line-by-line.
    - **Combine Linear Flows**: Create comprehensive "Happy Path" scenarios that validate the sequential flow of Intro, Pitch, Qualification, and Closing in one go. Do not split these into separate "Test Intro", "Test Pitch" items.
    - **Handle Branching Logic**: Only create separate scenarios when the path DIVERGES based on a specific user reply (e.g., "If user says they are a student, ask X; if working professional, ask Y").
    - **Integrate FAQs**: Weave simple FAQs (like "Price?", "Duration?") into the middle of larger scenarios to test natural handling, rather than isolating them unless they are complex.
    - **Guardrails**: Test negative constraints by attempting to breach them within a realistic flow.

    ---------------------------------------------------
    SECTION 2: INDIAN MARKET CONTEXT & UNEXPECTED SITUATIONS
    ---------------------------------------------------
    Generate "Real World" scenarios that are likely to happen.
    *IMPORTANT*: Describe the scenario directly. Do NOT use weird category prefixes.

    Topics to cover:
    - **Language Nuance**: "Hinglish" usage (e.g., "Price kya hai?", "Interest rate kitna lagega?", "Offer batao?", "Main interest nahi rakhta").
    - **Trust & Verification**: Users asking "Is this a real company?", "Send me details on WhatsApp first", "Fake call to nahi hai?".
    - **Decision Makers**: "Papa se pooch ke bataunga" (Will ask father), "Wife se discuss karna padega", "Ghar pe baat karni padegi".
    - **Negotiation**: "Isse kam nahi hoga?" (Can't it be lower?), "Baki log to sasta de rahe hain".
    - **Common User Behaviors**: 
       - "Abhi meeting mein hoon" (In a meeting, call later).
       - "Abhi drive kar raha hu" (Driving).
       - "Wrong Number" (pretending or real).
       - "Timepass" callers (chatty but no intent).
       - "Aggressive": "Kahan se number mila?" (Where did you get my number?).
    - **Logic Traps & Edge Cases**: 
       - **Contextual Overrides**: "I already have a course... actually, that was for SSC, I want Bank now" (Should be Interested).
       - **Conditional Intent**: "Interested only if you give a discount."
       - **Temporal Ambiguity**: "Kal subah dekhte hain" (Let's see tomorrow morning).
       - **Brand Loyalty**: "PhysicsWallah (or competitor) is better".

    ---------------------------------------------------
    CRITICAL EXCLUSIONS & FORMATTING RULES
    ---------------------------------------------------
    - **NO FRAGMENTATION**: Do not list "Check Intro", "Check Pitch" separately if they can be one "Lead listens to intro, accepts pitch, and asks for price" scenario.
    - **NO WEIRD PREFIXES**: Do NOT start scenarios with category names like "Indian Market Busy:", "The WhatsApp Lover:", "Logic Trap:", or "The Desi User:". 
    - **Start directly with the scenario description**: e.g., "User says they are driving...", "Lead asks for the price...".
    - Do NOT generate generic rule checks that apply to every call (e.g., "Verify tone", "Verify closing phrase", "Verify gender neutrality").
    - Do NOT output generic headers.
    - ONLY output specific, actionable scenario descriptions.

    Ensure coverage of:
    ${data.includeHappyPath ? "- Consolidated Happy paths." : ""}
    ${data.includeEdgeCases ? "- Edge cases & Logic Traps." : ""}
    ${data.includeNegative ? "- Negative/Adversarial flows." : ""}
    ${data.includeEntitySpecific ? "- Complex Data Extraction." : ""}

    FORMAT EXAMPLES (Follow this style):
    - "Lead goes through the full flow: listens to pitch, confirms eligibility, asks about price, and agrees to purchase." (Consolidated)
    - "Lead interrupts pitch to ask 'Kya ye government approved hai?' and then proceeds to show interest." (Integrated FAQ)
    - "Lead says 'Haan interest to hai par abhi paise nahi hain' (Interested but no money) - testing objection handling."
    - "User requests details be sent via WhatsApp and refuses to continue the call."

    The output must be a valid JSON object with a single property 'scenarios' which is an array of strings.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            scenarios: {
              type: Type.ARRAY,
              items: {
                type: Type.STRING
              }
            }
          }
        }
      }
    });

    const responseText = response.text;
    if (!responseText) {
        throw new Error("No response received from Gemini.");
    }

    const parsed: GeneratedResponse = JSON.parse(responseText);
    return parsed.scenarios;
  } catch (error) {
    console.error("Error generating scenarios:", error);
    throw new Error("Failed to generate scenarios. Please ensure your inputs are valid.");
  }
};

export const simulateScenario = async (
  scenarioText: string, 
  data: VoicebotFormData
): Promise<{ transcript: ChatMessage[], analysis: string }> => {
  if (!processApiKey) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey: processApiKey });

  const prompt = `
    You are a Voicebot Simulation Engine and QA Analyst.

    INPUTS:
    1. **Agent Profile**:
       - Name: ${data.agentName || "Agent"}
       - Instructions (System Prompt): "${data.mainPrompt}"
       - Business Use Case: "${data.businessUseCase}"

    2. **Lead Profile**:
       - Name: ${data.leadName || "Lead"}
       - Scenario to Enact: "${scenarioText}"
       - Instructions: Act exactly as this lead would in this specific scenario. Be completely human, natural, and reactive. Do not be robotic.

    TASK 1: SIMULATE THE CONVERSATION
    - Simulate a turn-by-turn conversation between the Agent and the Lead.
    - The **Agent** must STRICTLY follow the "Agent Profile" instructions. It does not know the scenario in advance.
    - The **Lead** must STRICTLY follow the "Scenario to Enact".
    - Continue the conversation until it reaches a natural conclusion (hang up, sale closed, or refusal).

    TASK 2: ANALYZE THE AGENT'S PERFORMANCE
    - Review the entire transcript.
    - Did the Agent fail to follow any instruction in the "Agent Profile"?
    - Did the Agent handle the specific "Scenario" correctly according to its logic?
    - Identify any hallucinations or logic breaks.
    - Output a concise analysis string for the "Bot Behavior Issue" column. If perfect, say "No issues found."

    OUTPUT FORMAT (JSON):
    {
      "transcript": [
        { "role": "agent", "text": "..." },
        { "role": "lead", "text": "..." }
      ],
      "analysis": "string"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            transcript: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  role: { type: Type.STRING },
                  text: { type: Type.STRING }
                }
              }
            },
            analysis: { type: Type.STRING }
          }
        }
      }
    });

    const responseText = response.text;
    if (!responseText) throw new Error("No response from simulation.");

    const parsed: SimulationResponse = JSON.parse(responseText);

    // Add detailed timestamps
    const startTime = new Date();
    const transcriptWithTime: ChatMessage[] = parsed.transcript.map((msg, index) => {
        // Increment time by a few seconds per message to look realistic
        const msgTime = new Date(startTime.getTime() + (index * 3500) + Math.random() * 1000);

        // Format: HH:mm:ss.SSS
        const hours = msgTime.getHours().toString().padStart(2, '0');
        const minutes = msgTime.getMinutes().toString().padStart(2, '0');
        const seconds = msgTime.getSeconds().toString().padStart(2, '0');
        const ms = msgTime.getMilliseconds().toString().padStart(3, '0');
        const timestamp = `${hours}:${minutes}:${seconds}.${ms}`;

        return {
            role: msg.role,
            text: msg.text,
            timestamp
        };
    });

    return {
        transcript: transcriptWithTime,
        analysis: parsed.analysis
    };

  } catch (error) {
    console.error("Simulation error:", error);
    throw new Error("Failed to simulate scenario.");
  }
};
